import json, re, os

def strip_ln(content):
    lines = content.split('\n')
    out = []
    for line in lines:
        m = re.match(r'^\d+: (.*)', line)
        if m:
            out.append(m.group(1))
            continue
        m = re.match(r'^\d+:$', line.rstrip('\r'))
        if m:
            out.append('')
            continue
        out.append(line)
    while out and out[-1] == '':
        out.pop()
    return '\n'.join(out) + '\n'

def extract_chunks(raw):
    """Extract chunked file content from raw string."""
    pattern = r'\{"content":"((?:[^"\\]|\\.)*?)","url":"(https://sourcegraph[^"]*?)"\}'
    matches = re.findall(pattern, raw)
    chunks = {}  # {rel_path: {(start,end): content}}

    for content_escaped, url in matches:
        # Skip non-chunked (clean) URLs
        if '%3F' not in url and '?L' not in url:
            continue

        file_m = re.search(r'/-/blob/(.+?)%3F', url)
        if not file_m:
            continue
        rel_path = file_m.group(1)

        line_range = re.search(r'%3FL(\d+)-(\d+)', url)
        if not line_range:
            continue
        start, end = int(line_range.group(1)), int(line_range.group(2))

        content = content_escaped.replace('\\n', '\n').replace('\\"', '"').replace('\\\\', '\\').replace('\\t', '\t').replace('\\r', '\r')

        if rel_path not in chunks:
            chunks[rel_path] = {}
        chunks[rel_path][(start, end)] = content

    return chunks

# Check current session JSONL
jsonl_path = '/logs/agent/sessions/projects/-workspace/320af8c1-2dd1-41cc-aa19-d3a83cbfd0b2.jsonl'
with open(jsonl_path) as f:
    raw = f.read()

chunks = extract_chunks(raw)
print("Chunks from JSONL:")
for path, ranges in sorted(chunks.items()):
    for (s, e), content in sorted(ranges.items()):
        # Find last line number in content
        last_num = None
        for line in reversed(content.split('\n')):
            m = re.match(r'^(\d+): ', line)
            if m:
                last_num = int(m.group(1))
                break
        print(f"  {path}: lines {s}-{e} (last_line={last_num})")

# Also check tool results
results_dir = '/logs/agent/sessions/projects/-workspace/320af8c1-2dd1-41cc-aa19-d3a83cbfd0b2/tool-results'
if os.path.exists(results_dir):
    for fname in sorted(os.listdir(results_dir)):
        fpath = os.path.join(results_dir, fname)
        with open(fpath, 'rb') as f:
            content_raw = f.read().decode('utf-8', errors='replace')
        file_chunks = extract_chunks(content_raw)
