import re

def strip_line_numbers(content):
    """Strip the 'N: ' prefix from each line in Sourcegraph file content."""
    lines = content.split('\n')
    result = []
    for line in lines:
        # Match "123: content" pattern
        m = re.match(r'^\d+: (.*)$', line)
        if m:
            result.append(m.group(1))
        elif line == '':
            result.append('')
        else:
            result.append(line)
    return '\n'.join(result)

